import{_ as e,c as a,o as t,a as p}from"./app.9ab4fef4.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[{"level":2,"title":"早岁已知世事艰，仍许飞鸿荡云间","slug":"早岁已知世事艰-仍许飞鸿荡云间","link":"#早岁已知世事艰-仍许飞鸿荡云间","children":[]},{"level":2,"title":"今日欢呼孙大圣，只缘妖雾又重来","slug":"今日欢呼孙大圣-只缘妖雾又重来","link":"#今日欢呼孙大圣-只缘妖雾又重来","children":[]},{"level":2,"title":"雄关漫道真如铁，而今迈步从头越","slug":"雄关漫道真如铁-而今迈步从头越","link":"#雄关漫道真如铁-而今迈步从头越","children":[]},{"level":2,"title":"遍地哀鸿满城血，无非一念救苍生","slug":"遍地哀鸿满城血-无非一念救苍生","link":"#遍地哀鸿满城血-无非一念救苍生","children":[]},{"level":2,"title":"今日长缨在手，何时缚住苍龙","slug":"今日长缨在手-何时缚住苍龙","link":"#今日长缨在手-何时缚住苍龙","children":[]}],"relativePath":"6.其他/问题解决/诗.md","lastUpdated":1688722215000}'),r={name:"6.其他/问题解决/诗.md"},i=p('<h2 id="早岁已知世事艰-仍许飞鸿荡云间" tabindex="-1">早岁已知世事艰，仍许飞鸿荡云间 <a class="header-anchor" href="#早岁已知世事艰-仍许飞鸿荡云间" aria-hidden="true">#</a></h2><p>蛊真人</p><p>早岁已知世事艰，仍许飞鸿荡云间。</p><p>一路寒风身如絮，命海沉浮客独行。</p><p>千磨万击心铸铁，殚精竭虑铸一剑。</p><p>今朝剑指叠云处，炼蛊炼人还炼天。</p><h2 id="今日欢呼孙大圣-只缘妖雾又重来" tabindex="-1">今日欢呼孙大圣，只缘妖雾又重来 <a class="header-anchor" href="#今日欢呼孙大圣-只缘妖雾又重来" aria-hidden="true">#</a></h2><p>毛泽东《七律·和郭沫若同志》</p><p>一从大地起风雷，便有精生白骨堆。 僧是愚氓犹可训，妖为鬼蜮必成灾。 金猴奋起千钧棒，玉宇澄清万里埃。 今日欢呼孙大圣，只缘妖雾又重来。</p><h2 id="雄关漫道真如铁-而今迈步从头越" tabindex="-1">雄关漫道真如铁，而今迈步从头越 <a class="header-anchor" href="#雄关漫道真如铁-而今迈步从头越" aria-hidden="true">#</a></h2><p>毛泽东《忆秦娥·娄山关》</p><p>西风烈，长空雁叫霜晨月。</p><p>霜晨月，马蹄声碎，喇叭声咽。</p><p>雄关漫道真如铁，而今迈步从头越。</p><p>从头越，苍山如海，残阳如血。</p><h2 id="遍地哀鸿满城血-无非一念救苍生" tabindex="-1">遍地哀鸿满城血，无非一念救苍生 <a class="header-anchor" href="#遍地哀鸿满城血-无非一念救苍生" aria-hidden="true">#</a></h2><p>毛泽东《七律·忆重庆谈判》</p><p>有田有地皆吾主，无法无天是为民。 重庆有官皆墨吏，延安无土不黄金。 炸桥挖路为团结，夺地争城是斗争。 遍地哀鸿满城血，无非一念救苍生。</p><h2 id="今日长缨在手-何时缚住苍龙" tabindex="-1">今日长缨在手，何时缚住苍龙 <a class="header-anchor" href="#今日长缨在手-何时缚住苍龙" aria-hidden="true">#</a></h2><p>毛泽东《清平乐·六盘山》</p><p>天高云淡，望断南飞雁。</p><p>不到长城非好汉，屈指行程二万。</p><p>六盘山上高峰，红旗漫卷西风。</p><p>今日长缨在手，何时缚住苍龙？</p>',24),d=[i];function l(n,h,s,c,_,o){return t(),a("div",null,d)}const m=e(r,[["render",l]]);export{f as __pageData,m as default};
